421	\section{Combined affine-corner finite-dimensionality consumer}
422	\label{sec:module_finite_HModule_prime_of_affine_iter042}
423	
424	The two consumers above each cover one degree side: the \(H^0\) consumer requires \(i = 0\), the positive-degree consumer requires \(i > 0\). We fold both into a single uniform statement covering all \(i \ge 0\).
425	
426	\begin{theorem}\leanok
427	[Combined affine-corner finite-dimensionality]
428	  \label{thm:Scheme_module_finite_HModule_prime_of_affine}
429	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine}
430	  
431	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules. Assume both affine cohomology vanishing and \(H^0\) Hom-finiteness hold for \(F\). For any affine open \(U\) of \(C\) and any \(i \ge 0\), the cohomology group \(H^{\prime i}(U, F)\) is finite-dimensional over \(k\).
432	\end{theorem}
433	
434	\begin{proof}
435	  
436	  \leanok
437	  Case-split on whether \(i = 0\) or \(i > 0\), delegating to the respective consumer.
438	\end{proof}
439	
440	\begin{theorem}\leanok
441	[Curve specialisation]
442	  \label{thm:Scheme_module_finite_HModule_prime_of_affine_curve}
443	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine_curve}
444	  
445	  Direct curve specialisation of Theorem~REF to \(F = \mathcal O_C\) for \(C\) a scheme over \(\Spec k\).
446	\end{theorem}
447	
448	\begin{proof}\uses{thm:Scheme_module_finite_HModule_prime_of_affine}
449	  Apply \cref{thm:Scheme_module_finite_HModule_prime_of_affine} with the
450	  sheaf of \(k\)-modules taken to be the structure sheaf \(F = \mathcal O_C\):
451	  the affine cohomology-vanishing and \(H^0\) Hom-finiteness hypotheses are
452	  exactly the curve hypotheses available for \(\mathcal O_C\), so every
453	  \(H^{\prime i}(U, \mathcal O_C)\) over an affine open \(U\) is
454	  finite-dimensional over \(k\). Proved directly in Lean.
455	\end{proof}
456	
457	\section{Wholespace \(H^0\) Hom-finiteness carrier}
458	\label{sec:IsHModuleHomFinite_iter043}
459	
460	The affine-quantified \(H^0\) Hom-finiteness class of Section~REF over-quantifies: on a non-trivial proper curve, sections over a proper affine open are typically infinite-dimensional over \(k\) (e.g. \(k[t]\) on \(\mathbb A^1_k\)). We introduce a corrective carrier that captures only the \emph{global} Hom group.
461	
462	\begin{definition}\leanok
463	[Wholespace \(H^0\) Hom-finiteness carrier predicate]
464	  \label{thm:Scheme_IsHModuleHomFinite}
465	  \lean{AlgebraicGeometry.Scheme.IsHModuleHomFinite}
466	  
467	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules on \(C\). The class of wholespace \(H^0\) Hom-finiteness asserts that the global morphism group \(\Hom(\text{constant sheaf at }k, F)\) is finite-dimensional over \(k\).
468	\end{definition}
469	
470	\begin{theorem}\leanok
471	[Finite-dimensionality of global \(H^0\) from wholespace Hom-finiteness]
472	  \label{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite}
473	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_of_isHModuleHomFinite}
474	  
475	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), and \(F\) a sheaf of \(k\)-modules. Assume wholespace \(H^0\) Hom-finiteness holds for \(F\). Then \(H^0_{\Module}(F)\) is finite-dimensional over \(k\).
476	\end{theorem}
477	
478	\begin{theorem}\leanok
479	[Curve specialisation]
480	  \label{thm:Scheme_module_finite_HModule_zero_of_isHModuleHomFinite_curve}
481	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule_zero_of_isHModuleHomFinite_curve}
482	  
483	  Direct curve specialisation of Theorem~REF to \(F = \mathcal O_C\).
484	\end{theorem}
485	
486	\begin{remark}
487	  On a proper geometrically connected curve, Stein factorization gives \(\Gamma(C, \mathcal O_C) = k\), which is finite-dimensional over \(k\). Thus the wholespace carrier is producible, unlike the affine-quantified version.
488	\end{remark}
489	
490	\section{Stein finiteness of global sections}
491	\label{sec:module_finite_globalSections_iter044}
492	
493	The geometric input for the wholespace Hom-finiteness carrier is Stein's theorem: on a proper integral scheme over a field, global sections are finite-dimensional.
494	
495	\begin{theorem}\mathlibok
496	[Module-finiteness of the top-section map of a universally closed morphism]
497	  \label{thm:finite_appTop_of_universallyClosed}
498	  \lean{AlgebraicGeometry.finite_appTop_of_universallyClosed}
499	
500	  Let \(K\) be a commutative ring and \(X\) an integral scheme equipped with a
501	  universally closed, locally-of-finite-type morphism \(f : X \to \Spec K\).
502	  Then the ring map on top sections \(f^\sharp_{\top}\) is module-finite.
503	
504	  \textit{Provided by Mathlib.}
505	\end{theorem}
506	
507	\begin{theorem}\leanok
508	[Stein finiteness of global sections]
509	  \label{thm:Scheme_module_finite_globalSections_of_isProper}
510	  \lean{AlgebraicGeometry.Scheme.module_finite_globalSections_of_isProper}
511	  \uses{thm:finite_appTop_of_universallyClosed, def:Scheme_kToSection}
512	
513	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then \(\Gamma(C, \mathcal O_C)\) is finite-dimensional over \(k\).
514	\end{theorem}
515	
516	\begin{proof}
517	  
518	  \leanok
519	  Apply the theorem that for an integral scheme with a universally closed, locally finite-type morphism to \(\Spec k\), the structure-morphism ring map on global sections is module-finite. Transfer the base ring from \(\Gamma(\Spec k, \top)\) to \(k\) along the canonical ring isomorphism.
520	\end{proof}
521	
522	\section{Global-sections evaluation isomorphism}
523	\label{sec:gammaObj_linearEquiv_top}
524	
525	To bridge from global sections (a concrete \(k\)-module) to the abstract Hom-from-constant-sheaf form, we lift the natural isomorphism between global sections and evaluation at the terminal object to a \(k\)-linear equivalence.
526	
527	\begin{theorem}\leanok
528	[Global-sections-to-top linear equivalence]
529	  \label{thm:Scheme_SheafGammaObj_linearEquiv_top}
530	  \lean{AlgebraicGeometry.Scheme.SheafGammaObj_linearEquiv_top}
531	  
532	  Let \(k\) be a field, \(X\) a topological space, and \(F\) a sheaf of \(k\)-modules on \(X\). Then there is a \(k\)-linear equivalence between the global-sections object of \(F\) and the evaluation of \(F\) at the top open \(\top\).
533	\end{theorem}
534	
535	\begin{theorem}\leanok
536	[Finite-dimensionality on global-sections object]
537	  \label{thm:Scheme_module_finite_gammaObj_of_isProper}
538	  \lean{AlgebraicGeometry.Scheme.module_finite_gammaObj_of_isProper}
539	  
540	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then the global-sections object of the \(k\)-module-valued structure sheaf is finite-dimensional over \(k\).
541	\end{theorem}
542	
543	\begin{proof}
544	  
545	  \leanok
546	  Combine Theorem~REF with the linear equivalence of Theorem~REF, transporting finite-dimensionality across the symmetric form.
547	\end{proof}
548	
549	\section{Producer instance for wholespace Hom-finiteness}
550	\label{sec:IsHModuleHomFinite_producer}
551	
552	We now assemble the chain: constant-sheaf/global-sections adjunction, Hom-from-\(k\) evaluation, and Stein finiteness, to produce the wholespace \(H^0\) Hom-finiteness instance.
553	
554	\begin{lemma}\leanok
555	[Linear lifting of adjoint functors]
556	  \label{lemma:Adjunction_left_adjoint_linear}
557	  \lean{CategoryTheory.Adjunction.left_adjoint_linear}
558	  Let \(F \dashv G\) be an adjunction between \(R\)-linear preadditive categories. If \(G\) is \(R\)-linear, then \(F\) is \(R\)-linear.
559	\end{lemma}
560	
561	\begin{lemma}\leanok
562	[Right-adjoint version]
563	  \label{lemma:Adjunction_right_adjoint_linear}
564	  \lean{CategoryTheory.Adjunction.right_adjoint_linear}
565	  Dual of Lemma~REF: if \(F\) is \(R\)-linear, then \(G\) is \(R\)-linear.
566	\end{lemma}
567	
568	\begin{theorem}\leanok
569	[Linear hom-equivalence from an adjunction]
570	  \label{def:Adjunction_homLinearEquiv}
571	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
572	  
573	  Let \(F \dashv G\) be an adjunction between \(R\)-linear preadditive categories with \(G\) additive and \(R\)-linear. Then for all objects \(X\) and \(Y\), the additive equivalence of the adjunction upgrades to an \(R\)-linear equivalence between \(\Hom(FX, Y)\) and \(\Hom(X, GY)\).
574	\end{theorem}
575	
576	\begin{theorem}\leanok
577	[Constant-sheaf / global-sections linear equivalence]
578	  \label{def:Scheme_constantSheafGammaHom_linearEquiv}
579	  \lean{AlgebraicGeometry.Scheme.constantSheafGammaHom_linearEquiv}
580	  
581	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules, and \(F\) a sheaf of \(k\)-modules. For any \(k\)-module \(X\), there is a \(k\)-linear equivalence between morphisms from the constant sheaf at \(X\) to \(F\), and \(k\)-linear maps from \(X\) to the global sections of \(F\).
582	\end{theorem}
583	
584	\begin{theorem}\leanok
585	[Hom-from-\(k\) evaluation]
586	  \label{def:Scheme_homFromOne_linearEquiv}
587	  \lean{AlgebraicGeometry.Scheme.homFromOne_linearEquiv}
588	  For any field \(k\) and \(k\)-module \(M\), there is a canonical \(k\)-linear equivalence between \(\Hom_k(k, M)\) and \(M\) given by evaluation at \(1\).
589	\end{theorem}
590	
591	\begin{theorem}\leanok
592	[Producer instance for wholespace Hom-finiteness]
593	  \label{inst:Scheme_instIsHModuleHomFinite_toModuleKSheaf}
594	  \lean{AlgebraicGeometry.Scheme.instIsHModuleHomFinite_toModuleKSheaf}
595	  
596	  Let \(k\) be a field and \(C\) an integral scheme over \(\Spec k\) with proper structure morphism. Then wholespace \(H^0\) Hom-finiteness holds for the \(k\)-module-valued structure sheaf of \(C\).
597	\end{theorem}
598	
599	\begin{proof}
600	  
601	  \leanok
602	  Compose the constant-sheaf/global-sections linear equivalence (specialised to \(X = k\)) with the Hom-from-\(k\) evaluation to obtain a linear equivalence between the global Hom group and the global-sections object. Theorem~REF provides finite-dimensionality on the latter; transport across the symmetric form of the equivalence.
603	\end{proof}
604	
605	\begin{remark}
606	  Once this producer instance is registered, the consumer of Theorem~REF fires automatically, closing \(H^0_{\Module}(\mathcal O_C)\) finite-dimensionality for proper integral curves.
607	\end{remark}
608	
609	\section{Foundational parameterised \v{C}ech infrastructure}
610	\label{sec:moduleK_cech_parameterised}
611	
612	We generalise the \v{C}ech carriers from the structure sheaf to an arbitrary sheaf of \(k\)-modules, laying the scaffolding for the \v{C}ech-vs-derived comparison theorem.
613	
614	\begin{definition}\leanok
615	[Parameterised \v{C}ech complex]
616	  \label{def:Scheme_cechCochain}
617	  \lean{AlgebraicGeometry.Scheme.cechCochain}
618	  
619	  Let \(C\) be a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules on \(C\), and \(\mathcal U\) an indexed family of opens. Define the \v{C}ech cochain complex of \(F\) with respect to \(\mathcal U\) to be the standard \v{C}ech complex applied to the underlying presheaf of \(F\). This is a cochain complex valued in \(k\)-modules.
620	\end{definition}
621	
622	\begin{definition}\leanok
623	[Parameterised \v{C}ech cohomology]
624	  \label{def:Scheme_cechCohomology}
625	  \lean{AlgebraicGeometry.Scheme.cechCohomology}
626	  
627	  With \((C, F, \mathcal U)\) as in Definition~REF, define the \(n\)-th \v{C}ech cohomology to be the \(n\)-th homology of the \v{C}ech cochain complex.
628	\end{definition}
629	
630	\begin{theorem}\leanok
631	[\v{C}ech complex bridge to structure-sheaf specialisation]
632	  \label{thm:Scheme_cechCochain_OC_eq}
633	  \lean{AlgebraicGeometry.Scheme.cechCochain_OC_eq}
634	  
635	  The structure-sheaf \v{C}ech complex equals the parameterised \v{C}ech complex at \(F = \mathcal O_C\).
636	\end{theorem}
637	
638	\begin{theorem}\leanok
639	[\v{C}ech cohomology bridge to structure-sheaf specialisation]
640	  \label{thm:Scheme_cechCohomology_OC_eq}
641	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC_eq}
642	  
643	  The structure-sheaf \v{C}ech cohomology equals the parameterised \v{C}ech cohomology at \(F = \mathcal O_C\).
644	\end{theorem}
645	
646	\begin{remark}
647	  These generalisations do not construct any comparison map between \v{C}ech and derived cohomology, nor do they prove vanishing. The substantive work is queued for subsequent iterations.
648	\end{remark}
649	
650	\section{\v{C}ech-side acyclicity carrier}
651	\label{sec:moduleK_cech_acyclic_cover}
652	
653	We introduce a carrier predicate capturing positive-degree vanishing of \v{C}ech cohomology, together with a consumer that transports this vanishing to derived cohomology once a comparison isomorphism is available.
654	
655	\begin{definition}\leanok
656	[\v{C}ech acyclicity carrier predicate]
657	  \label{def:Scheme_IsCechAcyclicCover}
658	  \lean{AlgebraicGeometry.Scheme.IsCechAcyclicCover}
659	  
660	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules on \(C\), and \(\mathcal U\) an indexed family of opens. The cover \(\mathcal U\) is \v{C}ech-acyclic for \(F\) if the \v{C}ech cohomology vanishes in positive degrees: for every \(n \ge 1\), the \(n\)-th \v{C}ech cohomology group is a subsingleton.
661	\end{definition}
662	
663	\begin{theorem}\leanok
664	[Derived vanishing from \v{C}ech acyclicity]
665	  \label{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover}
666	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover}
667	  
668	  Let \(k\) be a field, \(C\) a scheme over \(\Spec k\), \(F\) a sheaf of \(k\)-modules, and \(\mathcal U\) a \v{C}ech-acyclic cover for \(F\). Suppose there is a \(k\)-linear comparison isomorphism between \v{C}ech cohomology and derived cohomology of the cover supremum for every degree. Then for every \(n \ge 1\), the derived cohomology of the cover supremum is a subsingleton.
669	\end{theorem}
670	
671	\begin{proof}
672	  
673	  \leanok
674	  Transport the subsingleton structure along the symmetric form of the comparison isomorphism.
675	\end{proof}
676	
677	\begin{theorem}\leanok
678	[Curve specialisation]
679	  \label{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover_curve}
680	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover_curve}
681	  
682	  Curve specialisation of Theorem~REF at \(F = \mathcal O_C\).
683	\end{theorem}
684	
685	\section{Use in the project}
686	
687	The composition of the four typeclass instances of Sections~REF--REF, Definition~REF, and Definition~REF delivers Phase~A step~5 in full and bridges to Phase~A step~6:
688	
689	\begin{itemize}
690	  \item For \(C\) a scheme over \(\Spec k\), the \(k\)-module-valued cohomology \(H^n_{\Module}(\mathcal O_C)\) is well-defined and automatically carries a \(k\)-module structure, so \(\dim_k H^n_{\Module}(\mathcal O_C)\) is well-defined.
691	  \item Forgetting the \(k\)-module structure recovers the abelian-group cohomology of Chapter~REF, so the two theories commute on the underlying type level.
692	  \item Phase~A step~6 (Serre finiteness) remains the deep work to come, but is now expressible inside the standard \(k\)-module API: the statement becomes the finite-dimensionality predicate on \(H^n_{\Module}(F)\).
693	\end{itemize}
